                return false;
            } catch (IOException e) {
                if (attempt < maxRetries - 1) {
                    Thread.sleep(backoffMs);
                    backoffMs *= 2;
                } else {
                    throw e;
                }
            }
        }
        return false;
    }

    public static void main(String[] args) throws Exception {
        startServer();
        Thread.sleep(500);

        try {
            boolean success = client();
            System.exit(success ? 0 : 1);
        } finally {
            stopServer();
        }
    }
}
